    @Override
    public Class<?> findClass(String name) {
        if (name == null) return null;
        // Dispatch per package. Nested classes like
        // com.codename1.ui.Picker.LightweightPopupButtonPlacement
        // are resolved by walking the dotted name back until a
        // known package prefix matches. Only the matched package's
        // helper class loads — the rest stay cold. That removes the
        // eager Map<String, Class<?>> build from <clinit> time.
        String candidate = name;
        while (candidate != null) {
            int lastDot = candidate.lastIndexOf('.');
            if (lastDot < 0) return null;
            String pkg = candidate.substring(0, lastDot);
            Class<?> found = findClassInPackage(pkg, name);
            if (found != null) return found;
            candidate = pkg;
        }
        return null;
    }

